let fileContent = "";
try {
  const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, 'recruiters');
  fileContent = binaryBuffer.toString('utf8');
} catch (e) {
  throw new Error("Failed to read binary recruiters file: " + e.message);
}

let processedEmails = "";
try {
  const pBuffer = await this.helpers.getBinaryDataBuffer(0, 'processedEmails');
  processedEmails = pBuffer.toString('utf8');
} catch (e) {
  // File might be empty, ignore
}
const sentEmailsArray = processedEmails.split('\n').map(e => e.trim());

let posts;
try {
  posts = JSON.parse(fileContent);
} catch (e) {
  const snippet = fileContent.substring(0, 150);
  throw new Error(`Failed to parse JSON. First 150 chars: "${snippet}" | Error: ${e.message}`);
}

const recruiters = [];
for (const post of posts) {
  if (post.emails && post.emails.length > 0) {
    for (let email of post.emails) {
      email = email.trim().replace(/\.+$/, "");
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (emailRegex.test(email) && !sentEmailsArray.includes(email)) {
        recruiters.push({
          recruiter_name: post.poster_name || "Hiring Team",
          company: post.company || "",
          email: email,
          post_text: post.text || "",
          time_posted: post.time_posted || ""
        });
      }
    }
  }
}

return recruiters.map(r => ({ json: r }));

const groqResponse = $input.item.json;
const recruiter = $('Split In Batches').all(0, $runIndex)[0].json;

let customizedCoverLetter = "";
let fallbackTemplate = "Dear " + (recruiter.recruiter_name || "Hiring Team") + ",\n\nI came across your post and I am highly interested in the opportunity.\n\nI have experience in Full Stack development with React, Next.js, TypeScript, and Node.js. I am a quick learner and I can easily mold into your tech stack to start contributing effectively.\n\nYou can view my resume here: https://drive.google.com/file/d/1bjhBnMVeGDNWFr7yFraxt7_l_I1Ivyf9/view?usp=sharing\n\nBest regards,\nBibhuti";

try {
  const message = groqResponse.choices[0].message;
  let content = message.content || "";

  // Strip out any <think> blocks in case the API still generates them
  content = content.replace(/<think>[\s\S]*?<\/think>/gi, "").trim();

  // Extract JSON object safely
  const jsonStart = content.indexOf('{');
  const jsonEnd = content.lastIndexOf('}');

  if (jsonStart !== -1 && jsonEnd !== -1) {
    const jsonStr = content.slice(jsonStart, jsonEnd + 1);
    const parsed = JSON.parse(jsonStr);
    customizedCoverLetter = parsed.cover_letter || "";
  }

  // Failsafe
  if (!customizedCoverLetter || customizedCoverLetter.length < 50 || (!customizedCoverLetter.includes("Dear ") && !customizedCoverLetter.includes("Hi "))) {
    customizedCoverLetter = fallbackTemplate;
  }
} catch (e) {
  customizedCoverLetter = fallbackTemplate;
}

return {
  json: {
    ...recruiter,
    customized_cover_letter: customizedCoverLetter
  }
};

const recruiter = $('Split In Batches').all(0, $runIndex)[0].json;
const email = recruiter.email + '\n';
return {
  json: $input.item.json,
  binary: {
    ...$input.item.binary,
    logData: {
      data: Buffer.from(email).toString('base64'),
      mimeType: 'text/plain',
      fileName: 'log.txt'
    }
  }
};

// Native Wait nodes suspend the workflow to the DB, which can reset loop states in n8n V1.
// We use a simple JS delay instead to keep the loop memory intact.
await new Promise(resolve => setTimeout(resolve, 30000));
return $input.all();
